#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;



vec2 uv1 = (vUv-.5);// * uAspect.xy;
vec2 uv6 = uv1;

//##hier unten statt - auch plus
float z = 12*length((abs(uv1.x)-abs(uv1.y)));
//z = length(uv1)*22;

vec2 d = normalize(uv1);
if (q28%2==0) {d = q1*d-q2*1/d;}

vec2 rs = clamp(tan(z)*d,-4,4);
uv1 += -.06*lum(GetBlur1(vUv))*normalize(uv1);
uv1 -= rs/60; //auch minus und frac versuchen

uv6 = .4*cos(uv1*2*q28);
float bright = lum(GetBlur2(vec2(.55,.55)));
mus = .0006/(length(uv6)-.002*(q27+8*q28));
mus = clamp01(mus)*q31;
mus *= (1+roam_cos);
//mus = .2;


//probier auch 1*z;
vec3 crisp= texture(sampler_main,uv1*(.8+(.2)*z)+.5);

vec3 ret1 = crisp + mus;

q25 = q24+.5; //##hier auf 1 setzen
q25 = q24*.5+.5;
q25 = .4;
ret = q25*(ret1*.95-.025) + (1-q25)* texture(sampler_main,vUvOriginal) ;
ret = ret * (1-0*bright);

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uv0 = vUv;
vec2 uv5 = (vUv-.5)*uAspect.xy;

vUv -= 0.5;
vUv *= uAspect.xy;
vUv += vec2 (q5,q6)/4;
uv5 = vUv;
vUv = multiply(vUv,mat2(_qb));

rs0.x = atan(uv5.y, uv5.x)/3.1416*6*q28;
float k1 = 16*log(1/(length(vUv)));
rs0.y = k1;
//rs0.y = q5* k1 + q6 * 1/k1 ;
rss = vec2 (rs0.x+q9*4,rs0.y+q9*q28*4)/12;


vec3 ret1 = 0;
int anz = 3;
int n = 0;
vec2 ofs = .1*vec2(q5,q6).yx;
while (n <= anz) {
    float dist = fract(-q9+1.0*n/anz);

    ang2 = 6.28*n/anz;
    c = cos(ang2);
    s = sin(ang2);
    uv2 = multiply(vUv,q13*dist*mat2(c,s,-s,c))*uAspect.yx;
    uv3 = fract(uv2+.5+ofs) ;
    neu = 3*texture(sampler_main,uv3)+ GetBlur1(uv3)*0;
    ret1 = max(ret1,neu* (1-dist*dist));
n++;
}

vec2 dz = vec2 (ret1.r+ret1.b, ret1.r-ret1.g)/2;
ret2 = GetBlur1(fract(rss+dz))/k1*64;
ret = ret1 + audioLowSmooth*.004/length(vUv)*roam_sin
+ sqrt(ret2.brg)*clamp01(1-ret1*4);
//ret = GetPixel(uv0)*2;

  fragColor = ret;
}
